                v_offset: (v_offset_acc[qi] / tw) as f32,
                weight: tw as f32,
            });
        } else {
            avg_corrections.push(QualifierCorrection {
                h_center: qual.h_center,
                h_width: qual.h_width,
                h_offset: 0.0,
                s_ratio: 1.0,
                v_offset: 0.0,
                weight: 0.0,
